package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

// Define custom metrics with labels
var (
	userRequestCount = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_request_count",
			Help: "Total number of requests per user",
		},
		[]string{"username"},
	)
	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "request_duration_seconds",
			Help:    "Duration of HTTP requests in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"username", "endpoint"},
	)
)

func init() {
	// Register custom metrics with Prometheus
	prometheus.MustRegister(userRequestCount)
	prometheus.MustRegister(requestDuration)
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("user")
	endpoint := r.URL.Path

	if username == "" {
		http.Error(w, "Missing 'user' parameter", http.StatusBadRequest)
		return
	}

	// Increment request count for the user
	userRequestCount.WithLabelValues(username).Inc()

	// Measure request duration
	timer := prometheus.NewTimer(requestDuration.WithLabelValues(username, endpoint))
	defer timer.ObserveTotal()

	// Simulate a request processing delay
	http.ServeFile(w, r, "index.html")
}

func main() {
	http.HandleFunc("/", handleRequest)
	http.Handle("/metrics", promhttp.Handler())

	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}